import OpenAI from "openai";
import process from 'process';

// 初始化 openai 客户端
const openai = new OpenAI({
    apiKey: process.env.DASHSCOPE_API_KEY, // 从环境变量读取
    baseURL: 'https://[workspace-id].cn-beijing.maas.aliyuncs.com/compatible-mode/v1'
});
let isAnswering = false;
async function main() {
    try {
        const messages = [{ role: 'user', content: '你是谁' }];
        const stream = await openai.chat.completions.create({
            model: 'qwen3-max',
            messages,
            stream: true,
            enable_thinking: true
        });
        console.log('\n' + '='.repeat(20) + '思考过程' + '='.repeat(20));
        for await (const chunk of stream) {
            if (!chunk.choices.length) continue;
            const delta = chunk.choices[0].delta;
            if (delta.reasoning_content !== undefined && delta.reasoning_content !== null) {
                if (!isAnswering) {
                    process.stdout.write(delta.reasoning_content);
                }
            }
            if (delta.content !== undefined && delta.content) {
                if (!isAnswering) {
                    console.log('\n' + '='.repeat(20) + '完整回复' + '='.repeat(20));
                    isAnswering = true;
                }
                process.stdout.write(delta.content);
            }
        }
    } catch (error) {
        console.error('Error:', error);
    }
}
main();

responsesAPI.node:
import OpenAI from "openai";

const openai = new OpenAI({
    apiKey: process.env.DASHSCOPE_API_KEY,
    baseURL: "https://[workspace-id].cn-beijing.maas.aliyuncs.com/api/v2/apps/protocols/compatible-mode/v1"
});

async function main() {
    const response = await openai.responses.create({
        model: "qwen3-max",
        input: "9.9和9.11哪个大？",
        enable_thinking: true  // 启用思考模式
    });

    // 遍历输出项
    for (const item of response.output) {
        if (item.type === "reasoning") {
            console.log("【推理过程】");
            for (const summary of item.summary) {
                console.log(summary.text.substring(0, 500));
            }
            console.log();
        } else if (item.type === "message") {
            console.log("【最终答案】");
            console.log(item.content[0].text);
        }
    }
}

main();

